import * as React from 'react';
import Box from '@mui/material/Box';
import AppBar from '@mui/material/AppBar';
import Button from '@mui/material/Button';
import Grid from '@mui/material/Grid';

import { useNavigate } from 'react-router-dom';

// import Daylight from './collections/Daylight';
// import Dust from './collections/Dust';
// import Escape from './collections/Escape';
// import Illusion from './collections/Illusion';
// import Mountains from './collections/Mountains';
// import NiceDream from './collections/NiceDream';
// import RoseGold from './collections/RoseGold';
// import Stay from './collections/Stay';
// import Times from './collections/Times';
// import Voyages from './collections/Voyages';

function SubHeader () {
  const navigate = useNavigate();

  return (
    <>
      <AppBar
        position='static'
        color='inherit'
        sx={{
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          boxShadow: '0px 0px 0px #e3e3e3',
          backgroundColor: 'red',
          marginTop: {
            xs: '86px', // needs fixing
            sm: '86px', // needs fixing
            md: '86px',
            lg: '86px',
            xl: '86px',
          }
        }}
      >
        <Box
          sx={{
            display: {
              xs: 'none', // 2 columns menu
              sm: 'none', // 4 columns menu
              md: 'block'
            },
            marginLeft: '50px',
            marginRight: '50px',
            backgroundColor: 'blue'
          }}
        >
          <Button onClick={() => navigate('/collections/daylight')} color='inherit'>Daylight</Button>
          <Button onClick={() => navigate('/collections/dust')} color='inherit'>Dust</Button>
          <Button onClick={() => navigate('/collections/escape')} color='inherit'>Escape</Button>
          <Button onClick={() => navigate('/collections/illusion')} color='inherit'>Illusion</Button>
          <Button onClick={() => navigate('/collections/mountains')} color='inherit'>Mountains</Button>
          <Button onClick={() => navigate('/collections/nicedream')} color='inherit'>Nice Dream</Button>
          <Button onClick={() => navigate('/collections/rosegold')} color='inherit'>Rose Gold</Button>
          <Button onClick={() => navigate('/collections/stay')} color='inherit'>Stay</Button>
          <Button onClick={() => navigate('/collections/times')} color='inherit'>Times</Button>
          <Button onClick={() => navigate('/collections/voyages')} color='inherit'>Voyages</Button>
        </Box>

        <Box
          sx={{
            display: {
              xs: 'block',  // 2 columns menu
              sm: 'block',   // 4 columns menu
              md: 'none'
            },
            marginLeft: '50px',
            marginRight: '50px',
            backgroundColor: 'yellow',
          }}
        >
          <Grid container columns={{ xs: 3, sm: 5 }}>
            <Grid item xs={1} sm={1}>
              <Button onClick={() => navigate('/collections/daylight')} color='inherit'>Daylight</Button>
            </Grid>
            <Grid item xs={1} sm={1}>
              <Button onClick={() => navigate('/collections/dust')} color='inherit'>Dust</Button>
            </Grid>
            <Grid item xs={1} sm={1}>
              <Button onClick={() => navigate('/collections/escape')} color='inherit'>Escape</Button>
            </Grid>
            <Grid item xs={1} sm={1}>
              <Button onClick={() => navigate('/collections/illusion')} color='inherit'>Illusion</Button>
            </Grid>
            <Grid item xs={1} sm={1}>
              <Button onClick={() => navigate('/collections/mountains')} color='inherit'>Mountains</Button>
            </Grid>
            <Grid item xs={1} sm={1}>
              <Button onClick={() => navigate('/collections/nicedream')} color='inherit'>Nice Dream</Button>
            </Grid>
            <Grid item xs={1} sm={1}>
              <Button onClick={() => navigate('/collections/rosegold')} color='inherit'>Rose Gold</Button>
            </Grid>
            <Grid item xs={1} sm={1}>
              <Button onClick={() => navigate('/collections/stay')} color='inherit'>Stay</Button>
            </Grid>
            <Grid item xs={1} sm={1}>
              <Button onClick={() => navigate('/collections/times')} color='inherit'>Times</Button>
            </Grid>
            <Grid item xs={1} sm={1}>
              <Button onClick={() => navigate('/collections/voyages')} color='inherit'>Voyages</Button>
            </Grid>
          </Grid>
        </Box>
      </AppBar>
    </>
  )
}

export default SubHeader;
